-- =========================================================
-- DATABASE SCHEMA & PRE-SEEDED CONTENT FOR DAR'EE APPLICATION
-- Target Engine: MySQL / MariaDB (Supports utf8mb4 encoding)
-- =========================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ---------------------------------------------------------
-- Table structure for TABLE users
-- ---------------------------------------------------------
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `username` varchar(100) NOT NULL PRIMARY KEY,
  `email` varchar(255) NOT NULL,
  `password` varchar(255) NOT NULL,
  `name` varchar(255) NOT NULL,
  `role` varchar(50) NOT NULL DEFAULT 'user',
  `avatar_seed` varchar(100) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------
-- Table structure for TABLE books
-- ---------------------------------------------------------
DROP TABLE IF EXISTS `books`;
CREATE TABLE `books` (
  `id` varchar(50) NOT NULL PRIMARY KEY,
  `title` varchar(255) NOT NULL,
  `author` varchar(255) NOT NULL,
  `editor` varchar(255) DEFAULT NULL,
  `category` varchar(100) NOT NULL,
  `description` text NOT NULL,
  `publish_date` varchar(100) NOT NULL,
  `read_time` varchar(100) NOT NULL,
  `is_free` tinyint(1) NOT NULL DEFAULT 1,
  `price` int(11) NOT NULL DEFAULT 0,
  `rating` decimal(3,1) DEFAULT 5.0,
  `views` int(11) NOT NULL DEFAULT 0,
  `cover_image` varchar(500) DEFAULT NULL,
  `cover_style` text NOT NULL, -- JSON string representation
  `content` longtext NOT NULL, -- JSON array of chapters
  `free_copy_content` longtext DEFAULT NULL,
  `drive_pdf_url` varchar(500) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------
-- Table structure for TABLE articles
-- ---------------------------------------------------------
DROP TABLE IF EXISTS `articles`;
CREATE TABLE `articles` (
  `id` varchar(50) NOT NULL PRIMARY KEY,
  `title` varchar(255) NOT NULL,
  `author` varchar(255) NOT NULL,
  `category` varchar(100) NOT NULL,
  `description` text DEFAULT NULL,
  `cover_image` varchar(500) DEFAULT NULL,
  `image_style` text NOT NULL, -- JSON string representation
  `content` longtext NOT NULL, -- JSON array of paragraphs
  `rich_content` longtext DEFAULT NULL, -- JSON formatted elements
  `read_time` varchar(100) NOT NULL,
  `date` varchar(100) NOT NULL,
  `views` int(11) NOT NULL DEFAULT 0,
  `likes` int(11) NOT NULL DEFAULT 0,
  `rating` decimal(3,1) DEFAULT 5.0,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------
-- Table structure for TABLE thoughts
-- ---------------------------------------------------------
DROP TABLE IF EXISTS `thoughts`;
CREATE TABLE `thoughts` (
  `id` varchar(50) NOT NULL PRIMARY KEY,
  `title` varchar(255) DEFAULT NULL,
  `content` text NOT NULL,
  `author` varchar(255) NOT NULL,
  `category` varchar(100) NOT NULL,
  `date` varchar(100) NOT NULL,
  `likes` int(11) NOT NULL DEFAULT 0,
  `rating` decimal(3,1) DEFAULT 5.0,
  `views` int(11) NOT NULL DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------
-- Table structure for TABLE reviews
-- ---------------------------------------------------------
DROP TABLE IF EXISTS `reviews`;
CREATE TABLE `reviews` (
  `id` varchar(50) NOT NULL PRIMARY KEY,
  `item_id` varchar(50) NOT NULL,
  `author_name` varchar(255) NOT NULL,
  `content` text NOT NULL,
  `rating` int(11) DEFAULT NULL,
  `date` varchar(100) NOT NULL,
  `user_id` varchar(50) NOT NULL,
  `replies` longtext DEFAULT NULL, -- JSON array of reply objects
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------
-- Table structure for TABLE welcome_audio
-- ---------------------------------------------------------
DROP TABLE IF EXISTS `welcome_audio`;
CREATE TABLE `welcome_audio` (
  `id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY,
  `audio` longtext NOT NULL, -- contains active Base64 audio representation
  `filename` varchar(255) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

