INSERT INTO `books` (`id`, `title`, `author`, `editor`, `category`, `description`, `publish_date`, `read_time`, `is_free`, `price`, `rating`, `views`, `cover_image`, `cover_style`, `content`, `free_copy_content`, `drive_pdf_url`) 
VALUES ('b-wasitiyyah', 'العقيدة الواسطية', 'شيخ الإسلام ابن تيمية', 'أبو حاتم الدرعي', 'عقيدة وتوحيد', 'متن العقيدة الواسطية الشهير لشيخ الإسلام ابن تيمية رحمه الله، وعناية المحرر أبو حاتم الدرعي، يُعنى بتقرير عقيدة أهل السنة والجماعة بأدلة محكمة من الكتاب والسنة.', 'ذو الحجة ١٤٤٧هـ', '٣٠ دقيقة بقراءة متمهلة', 1, 0, 5, 0, '/src/assets/images/wasitiyyah_cover_1781346210533.jpg', '{"bg":"from-amber-900 via-rose-950 to-stone-900","text":"text-amber-50","accent":"border-amber-400 bg-amber-500/25 text-amber-200","pattern":"geometric"}', '["مقدمة العناية بالمتن - بقلم المحرر أبو حاتم الدرعي:\\nالحمد لله وحده والصلاة والسلام على رسول الله وعلى آله وصحبه، ومن اقتدى بهداه إلى قيامة الساعة.\\n\\nوبعد: فقد تم بحمد الله وفضله العناية بمتن (العقيدة الواسطية لشيخ الإسلام ابن تيمية رحمه الله)، وقد حاولت الاختصار ما استطعت; حتى تصل إلى القارئ بأفضل حله، وقد اعتنيت بها من جهة آيات المصحف، وتخريج الأحاديث مستعينًا بصحيحي البخاري ومسلم وببعض كتب الشيخ الألباني والشيخ مقبل الوادعي -رحمهم الله جميعا-، واعتنيت بالنص ورتبته ونسقته، واعتمدت الأصح من النسخ التي اطلعت عليها منها المطبوع ومخطوطة واحدة، ولم أذكر تفاصيل النسخ والكلام على كل صغيرة وكبيرة وفضلت الاختصار; فالمتن مختصر، وكذلك عنايتي به مختصرة، وإن شاء الله في وقت لاحق أقوم بشرحها والاهتمام بها أكثر إن أمد الله في العمر.\\n\\nوما كان من خطأ او سهو في طياته فذلك خطأ مني، وادعو الله عزوجل أن يسامحني، وأن يدلني على الصواب إنه ولي ذلك والقادر عليه، ومن رأى خطأ وأرشدني له فله الأجر والثواب من الله.","الفصل الأول: البسملة والحمدلة وباب الإيمان بالله وصفاته:\\nبِسْمِ اللهِ الرَّحْمَنِ الرَّحِيمِ\\n\\nالْحَمْدُ للهِ الَّذِي أَرْسَلَ رَسُولَهُ بِالْهُدَى وَدِينِ الْحَقِّ لِيُظْهِرَهُ عَلَى الدِّينِ كُلِّهِ وَكَفَى بِاللهِ شَهِيداً، وَأَشْهَدُ أَن لاَّ إِلَهَ إِلاَّ اللهُ وَحْدَهُ لاَ شَرِيكَ لَهُ إِقْرَاراً بِهِ وَتَوْحِيداً، وَأَشْهَدُ أَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ صَلَّى اللهُ عَلَيْهِ وَعَلَى آلِهِ وَصَحْبِهِ وَسَلَّمَ تَسْلِيماً مَزِيداً.\\n\\nأَمَّا بَعْدُ: فَهَذَا اعْتِقَادُ الْفِرْقَةِ النَّاجِيَةِ الْمَنْصُورَةِ إِلَى قِيَامِ السَّاعَةِ - أَهْلِ السُّنَّةِ وَالْجَمَاعَةِ - وَهُوَ: الإِيمَانُ بِاللهِ، وَمَلاَئِكَتِهِ، وَكُتُبِهِ، وَرُسُلِهِ، وَالْبَعْثِ بَعْدَ الْمَوْتِ، وَالإِيمَانُ بِالْقَدَرِ خَيْرِهِ وَشَرِّهِ.\\n\\nوَمِنَ الإِيمَانِ بِاللهِ: الإِيمَانُ بِمَا وَصَفَ بِهِ نَفْسَهُ فِي كِتَابِهِ، وَبِمَا وَصَفَهُ بِهِ رَسُولُهُ مُحَمَّدٌ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، مِنْ غَيْرِ تَحْرِيفٍ وَلاَ تَعْطِيلٍ، وَمِنْ غَيْرِ تَكْيِيفٍ وَلاَ تَمْثِيلٍ. بَلْ يُؤْمِنُونَ بِأَنَّ اللهَ سُبْحَانَهُ {لَيْسَ كَمِثْلِهِ شَيْءٌ وَهُوَ السَّمِيعُ الْبَصِيرُ} [الشورى: 11]."]', 'مقدمة العناية بالمتن - بقلم المحرر أبو حاتم الدرعي:
الحمد لله وحده والصلاة والسلام على رسول الله وعلى آله وصحبه، ومن اقتدى بهداه إلى قيامة الساعة.
وبعد: فقد تم بحمد الله وفضله العناية بمتن (العقيدة الواسطية لشيخ الإسلام ابن تيمية رحمه الله)، وقد حاولت الاختصار ما استطعت; حتى تصل إلى القارئ بأفضل حله، وقد اعتنيت بها من جهة آيات المصحف، وتخريج الأحاديث مستعينًا بصحيحي البخاري ومسلم وببعض كتب الشيخ الألباني والشيخ مقبل الوادعي -رحمهم الله جميعا-، واعتنيت بالنص ورتبته ونسقته، واعتمدت الأصح من النسخ التي اطلعت عليها منها المطبوع ومخطوطة واحدة، ولم أذكر تفاصيل النسخ والكلام على كل صغيرة وكبيرة وفضلت الاختصار; فالمتن مختصر، وكذلك عنايتي به مختصرة، وإن شاء الله في وقت لاحق أقوم بشرحها والاهتمام بها أكثر إن أمد الله في العمر.
وما كان من خطأ او سهو في طياته فذلك خطأ مني، وادعو الله عزوجل أن يسامحني، وأن يدلني على الصواب إنه ولي ذلك والقادر عليه، ومن رأى خطأ وأرشدني له فله الأجر والثواب من الله.

-----------------------------
متن العقيدة الواسطية العريق:
أَمَّا بَعْدُ: فَهَذَا اعْتِقَادُ الْفِرْقَةِ النَّاجِيَةِ الْمَنْصُورَةِ إِلَى قِيَامِ السَّاعَةِ - أَهْلِ السُّنَّةِ وَالْجَمَاعَةِ - وَهُوَ: الإِيمَانُ بِاللهِ، وَمَلاَئِكَتِهِ، وَكُتُبِهِ، وَرُسُلِهِ، وَالْبَعْثِ بَعْدَ الْمَوْتِ، وَالإِيمَانُ بِالْقَدَرِ خَيْرِهِ وَشَرِّهِ.
وَمِنَ الإِيمَانِ بِاللهِ: الإِيمَانُ بِمَا وَصَفَ بِهِ نَفْسَهُ فِي كِتَابِهِ، وَبِمَا وَصَفَهُ بِهِ رَسُولُهُ مُحَمَّدٌ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، مِنْ غَيْرِ تَحْرِيفٍ وَلاَ تَعْطِيلٍ، وَمِنْ غَيْرِ تَكْيِيفٍ وَلاَ تَمْثِيلٍ...', 'https://drive.google.com/file/d/1KH8uJMd5BVBdPvL5nJVAjlxhWmhelECV/view?usp=sharing');

INSERT INTO `books` (`id`, `title`, `author`, `editor`, `category`, `description`, `publish_date`, `read_time`, `is_free`, `price`, `rating`, `views`, `cover_image`, `cover_style`, `content`, `free_copy_content`, `drive_pdf_url`) 
VALUES ('b-1', 'فلسفة السحاب والوجود', 'أديب الدرعي', NULL, 'فلسفة وتأمل', 'كتاب يستكشف العلاقة الرمزية بين السحب المتحركة في كبد السماء وحياة الإنسان الرحالة، متطرقاً إلى السلام الداخلي وقبول التغيير.', 'رجب ١٤٤٧هـ', '٤٥ دقيقة بقراءة متمهلة', 1, 0, 4.8, 0, 'https://images.unsplash.com/photo-1534447677768-be436bb09401?w=400&auto=format&fit=crop&q=80', '{"bg":"from-blue-600 via-indigo-700 to-indigo-900","text":"text-white","accent":"border-cyan-400 bg-cyan-500/20 text-cyan-200","pattern":"sky"}', '["الفصل الأول: هيبة الأفق البعيد\\nعندما نقف تحت السماء الواسعة، ينتابنا شعور بالضآلة، ليس تهميشاً لوجودنا، بل تعظيماً للكون الذي نحيا فيه. السحاب يمر فوقنا كرسائل صامتة تذكرنا بالتدفق والحرية.\\n\\nالغيوم لا تملك خريطة طريق ثابتة، ولكنها تسير بثقة يحركها نسيم خفيف، لا تعترض على الجبال بل تلتف حولها وتمر بأمان. هكذا ينبغي أن تكون الروح البشرية في مواجهة العقبات; مرنة، متدفقة، تسعى للارتفاع وتجود بالخير أينما حلت.","الفصل الثاني: فن الرحيل الصامت\\nإن السحب تعلمنا أعظم الدروس في فضيلة التخلي والتغيير المستمر. لا تقف الغيمة في مكان واحد لتندب حظها أو تطالب بالبقاء، بل تتحول بسلاسة من حالة البخار السابح إلى قطرات ندى أو حبات مطر تحيي النفوس والزرع.\\n\\nالولادة والإثمار والرحيل، كلها فصول في رواية عظيمة واحدة. عندما نقرأ هذا التناغم الطبيعي، نفهم أن بعض الفترات في حياتنا لا تحتاج منا التشبث العنيف، بل تحتاج الاستسلام الجميل لتيارات العطاء والتجدد الخلاق.","الفصل الثالث: النظر إلى الأعلى كعلاج نفسي\\nيعتاد البشر النظر إلى الأسفل، نحو هواتفهم، نحو مشاكلهم الأرضية، ونحو الشماتة والعقبات. لكن، جرب أن تستلقي على العشب الأخضر لخمس دقائق فقط، وتثبت عينيك في سماء زرقاء تسبح فيها غيوم بيضاء متفرقة.\\n\\nهذا التدريب العقلي يعيد ضبط رؤيتك للأمور. المشاكل الكبيرة تبدو كذرات غبار تافهة في فضاء لانهائي. إنه الاتصال بالمصدر، والاعتراف بأن هناك جمالاً يسير بنظام فائق الدقة لا يد لنا في صياغته سوى التأمل والتقدير الصادق له."]', NULL, NULL);

INSERT INTO `books` (`id`, `title`, `author`, `editor`, `category`, `description`, `publish_date`, `read_time`, `is_free`, `price`, `rating`, `views`, `cover_image`, `cover_style`, `content`, `free_copy_content`, `drive_pdf_url`) 
VALUES ('b-2', 'رحلتنا نحو الضياء', 'عبدالله الدرعي', NULL, 'تطوير الذات والروح', 'دليل عملي ووجداني يهدف إلى ارتقاء الفرد بروحه وفكره عبر تنظيم عادات الذهن والتأمل والتصالح مع الذات لتجاوز عثرات الحياة المعاصرة.', 'شعبان ١٤٤٧هـ', '٣٥ دقيقة', 0, 35, 4.9, 0, 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?w=400&auto=format&fit=crop&q=80', '{"bg":"from-emerald-700 via-teal-800 to-cyan-950","text":"text-white","accent":"border-emerald-400 bg-emerald-500/20 text-emerald-200","pattern":"minimal"}', '["المدخل: من الظلمة إلى التنوير\\nالضياء ليس كائناً خارجياً نبحث عنه في ركام المقتنيات أو كلمات المديح، الضياء بذرة في أعماقك مغطاة بغبار المشاغل اليومية والتوترات المستمرة.\\n\\nلتبدأ الرحلة، عليك بالتخلص من الأحمال غير الضرورية: الضغائن، الماضي الذي ولى، وتوقعات الآخرين المرهقة. خفف وزنك المعنوي لتطير الروح كطائر أبيض يبحث عن موطنه الحقيقي فوق السحاب.","الخطوة الأولى: السكوت الواعي\\nنعيش في عالم مليء بالضوضاء، الموسيقى، الإعلانات، المحادثات التافهة، والأخبار المفزعة. السكوت الواعي هو أن تقتطع من يومك نصف ساعة تقضيها في صمت كامل، تجلس مع نفسك، تستمع لدقات قلبك وتراقب تنفسك.\\n\\nالصمت ليس فراغاً، بل هو مليء بالإجابات التي تعجز الكلمات الصاخبة عن إيصالها إلى وعيك العميق. في الصمت نلتقي بالحقائق ونكتسب شجاعة الصدق البديهية التي تسبق التصرف الحكيم.","الخطوة الثانية: ممارسة الامتنان اليومي\\nكل صباح قبل أن تلمس هاتفك الذكي، اذكر ثلاثة أشياء في حياتك تشعر بالامتنان لوجودها: صحة جيدة، عائلة محبة، أو حتى كوب قهوة دافئ وجلسة آمنة.\\n\\nالامتنان يغير كيمياء الدماغ، ويجعلك تركز على ما تملك بدلاً مما ينقصك، مما يخلق وفرة نفسية تجذب إليك السلام والهدوء الداخلي وتجعلك بلسماً لكل من يحيط بك."]', NULL, NULL);

INSERT INTO `books` (`id`, `title`, `author`, `editor`, `category`, `description`, `publish_date`, `read_time`, `is_free`, `price`, `rating`, `views`, `cover_image`, `cover_style`, `content`, `free_copy_content`, `drive_pdf_url`) 
VALUES ('b-3', 'مخطوطات الروح وتاريخ الحكمة', 'د. مريم الدرعي', NULL, 'تاريخ وأدب', 'جولة تاريخية ماتعة بين أهم المكتبات في حضارتنا الإسلامية والإنسانية، مسلطة الضوء على قيمة الكلمة وتأثيرها على مر العصور والقرون المسطرة.', 'ربيع الأول ١٤٤٦هـ', '٦٠ دقيقة بقراءة واعية', 0, 49, 4.7, 0, 'https://images.unsplash.com/photo-1457369804613-52c61a468e7d?w=400&auto=format&fit=crop&q=80', '{"bg":"from-amber-700 via-amber-950 to-stone-900","text":"text-amber-50","accent":"border-amber-400 bg-amber-500/25 text-amber-200","pattern":"geometric"}', '["الباب الأول: بيت الحكمة البغدادي\\nفي قلب بغداد النابض، وفي عصرها الذهبي، تأسس ديوان الترجمة وبيت الحكمة ليصبح مناراً للعالم. لم يكن مجرد مخزن للكتب بل كان خلية نحل تضم العلماء من شتى بقاع الأرض.\\n\\nهناك، تلاقت لغات الهند واليونان وفارس باللغة العربية الفصحى الشاسعة، فتم تعريب العلوم وتصحيح النظريات ووضع أسس البحث العلمي الحديث الذي مهد الطريق للحضارة المعاصرة قاطبة.","الباب الثاني: مكتبة قرطبة الأندلسية\\nفي الغرب الإسلامي، كانت قرطبة مناراً للثقافة والأناقة الفكرية. امتلكت مكتبة الخليفة في قصر الحكم قرابة أربعمائة ألف مجلد مفهرسة بعناية نادرة وبخطوط بديعة.\\n\\nكانت النساء يعملن كوارقات ومترجمات ومصححات، في دلالة واضحة على ارتقاء الوعي المجتمعي وتقديره العميق لدور المرأة الفكري والتعليمي القيادي والريادي الرائع.","الباب الثالث: رسالة العصر الرقمي الحديث\\nبينما تطوى صفحات الكتب الورقية التاريخية الثمينة ببطء تحت وطأة الزمن، يفتح العالم الرقمي بوابات أوسع لا يعرف الحدود الجغرافية أو قيود النخب الضيقة.\\n\\nإن واجبنا اليوم هو تحويل هذا الطوفان من المعلومات المتاحة إلى منهل عذب من الحكمة الهادفة المؤثرة، حتى لا نفقد البوصلة الروحية في بحور الترويج السريع والمحتويات السطحية."]', NULL, NULL);


-- Seeding Articles --
INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-1', 'أهمية القراءة الهادئة في عصر التشتت الرقمي المفرط', 'أديب الدرعي', 'وعي فكري', NULL, 'https://images.unsplash.com/photo-1481627834876-b7833e8f5570?w=400&auto=format&fit=crop&q=80', '{"from":"from-blue-500","to":"to-indigo-600","pattern":"circles"}', '["نحن نعيش في حقبة تاريخية يتلقى فيها العقل البشري كمية هائلة من الإشعارات ومقاطع الفيديو القصيرة والنصوص المقتضبة، مما أثر سلباً على قدرتنا الجوهرية على التركيز المستمر والتأمل العميق البنّاء.","القراءة الهادئة للكتب الرقمية أو الورقية الخالية من المشتتات ليست مجرد وسيلة لاكتساب المعلومات، بل هي تمرين ممتاز لتدريب أعصاب الدماغ على الحفاظ على التركيز لمدة أطول، وتحسين الذاكرة العاملة والتحليل المنطقي.","لتستعيد هدوء ذهنك، خصص وقتاً هادئاً كأن يكون ٢٠ دقيقة يومياً قبل النوم مغلقاً فيها جميع برامج التواصل الاجتماعي، مستعرضاً فصلاً من كتاب يحمل قيمة فلسفية أو روحية، والنتيجة ستكون اتزاناً عقلياً ونوماً عميقاً هادئاً."]', NULL, '٧ دقائق تصفح', '١٠ يونيو ٢٠٢٦', 1240, 312, 4.8);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-2', 'تأملات تحت الغمام: كيف تلهم الطبيعة الأقلام العربية؟', 'مها الدرعي', 'أدب وبيئة', NULL, 'https://images.unsplash.com/photo-1447752875215-b2761acb3c5d?w=400&auto=format&fit=crop&q=80', '{"from":"from-sky-400","to":"to-blue-600","pattern":"clouds"}', '["منذ أيام الجاهلية وفي معلقات الكبار، كان للغيث والغيم والأطلال نصيب الأسد من التشبيهات الرائعة ومقدمات القصائد الفذة العصية على النسيان والتلاشي.","سحر الطبيعة وفيض غيومها ليس ترفاً صورياً، بل هو حوار عميق بين النفس البشرية بكل تقلباتها وشجونها، والكون الخارجي الذي يعيد صياغة مفاهيم الأمل بنزول المطر والربيع الزاهر.","أقلامنا المعاصرة تحتاج للعودة إلى مناهل الطبيعة العذراء، بدلاً من الاقتصار على جدران الإسمنت وخلفيات الأجهزة الافتراضية، لنستشعر جمال الحياة من نبض الطبيعة الحقيقية الناصع."]', NULL, '٥ دقائق تصفح', '٨ يونيو ٢٠٢٦', 890, 195, 4.7);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-3', 'أدب الخاطرة: الفارق بين الصرخة الوجدانية والمقال الفلسفي المنظم', 'سارة الدرعي', 'أدب ونقد', NULL, 'https://images.unsplash.com/photo-1455390582262-044cdead277a?w=400&auto=format&fit=crop&q=80', '{"from":"from-violet-500","to":"to-pink-600","pattern":"waves"}', '["الخاطرة هي ومضة فكرية، شعور طارئ يرسل دفقة عاطفية خاطفة يعبر عنها الكاتب دون قيود الهيكلة المنهجية أو شروط حجج البراهين المنطقية الصارمة.","أما المقال فهو بناء منظم، يحتاج الفكرة ومقدمتها وشرحها مع خاتمة متناسقة تقنع ذهن القارئ بالحجج العقلانية المنظمة والمستندات السليمة.","في مكتبتنا الرقمية، نسعى لمنح العقل كلتا التجربتين: جمال الخواطر التلقائي ودفئها العاطفي الأنيق، ورصانة المقالات وعمق فوائدها الفكرية المجدية."]', NULL, '٦ دقائق تصفح', '٣ يونيو ٢٠٢٦', 1105, 247, 4.5);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-4', 'قوة الكلمة الطيبة في بناء وعي المجتمعات المتماسكة', 'عبدالله الدرعي', 'وعي فكري', NULL, 'https://images.unsplash.com/photo-1544716278-ca5e3f4abd8c?w=400&auto=format&fit=crop&q=80', '{"from":"from-emerald-500","to":"to-teal-600","pattern":"circles"}', '["الكلمات التي نطلقها يومياً ليست حروفاً عابرة تذروها الرياح، بل هي بذور تُلقى في تربة المجتمع الخصبة، فإما أن تنبت زهوراً وارفة أو أشواكاً سامة.","بناء التماسك والتعاطف المجتمعي يبدأ من لغة الكلمات المشتركة التي نستخدمها في حواراتنا بمواقع التواصل وبيئات العمل الصديقة.","لنعاهد أنفسنا على التحلي بأدب اللفظ وسماحة الرد، حتى تسود المحبة ويبنى صرح قوي من الوعي المشترك الملتزم بالإنصاف والاعتدال والود."]', NULL, '٨ دقائق', '١ يونيو ٢٠٢٦', 935, 184, 4.9);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-5', 'كيف تبدأ صباحك بجرعة وافرة من السلام والسكينة؟', 'مها الدرعي', 'تطوير الذات والروح', NULL, 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=400&auto=format&fit=crop&q=80', '{"from":"from-amber-400","to":"to-amber-600","pattern":"clouds"}', '["إن السعة الداخلية التي تشعر بها في ساعات الصباح الأولى هي رأسمالك الحقيقي لتجاوز توترات وتحديات ساعات النهار القادمة بنجاح مذهل.","تجنب لمس الأجهزة الإلكترونية في أول نصف ساعة من يومك، واستبدلها بتأمل صامت لغرائب الطبيعة أو قراءة صفحة وجيزة من أثير الفكر.","تنفس بعمق، واستنشق عبير الرضا التام والامتنان الصافي لله على نعمة الحياة الآمنة والهواء النقي، لتكون يوميتك سلسلة من البركات البهية."]', NULL, '٦ دقائق', '٢٨ مايو ٢٠٢٦', 750, 210, 4.8);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-6', 'العقل النقدي: فن التمييز بين المعلومات المفيدة والغث المتناقل', 'أبو حاتم الدرعي', 'وعي فكري', NULL, 'https://images.unsplash.com/photo-1507842217343-583bb7270b66?w=400&auto=format&fit=crop&q=80', '{"from":"from-indigo-500","to":"to-indigo-700","pattern":"waves"}', '["الانفجار المعرفي السريع الذي تشهده محركات البحث وشبكات الويب يحتاج منا تبني فكر نقدي حازم لا يقبل الادعاءات بلا أدلة علمية واضحة.","ليس كل ما يلتمع تحت بند (دراسة حديثة) هو حقيقة مطلقة، القارئ اللطيف يستقصي مصادر الأخبار ويقارن النظريات بالبراهين المنطقية.","تثقيف العقل على التروي وعدم العجلة من أجل إطلاق الأحكام هو أولى الخطوات نحو الخلاص والريادة المعرفية السليمة."]', NULL, '٩ دقائق', '٢٢ مايو ٢٠٢٦', 1420, 289, 4.9);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-7', 'فلسفة الصمت والاصغاء في عالم يتوق للتحدث والصحب', 'صالح الدرعي', 'فلسفة وتأمل', NULL, 'https://images.unsplash.com/photo-1518241353330-0f7941c2d9b5?w=400&auto=format&fit=crop&q=80', '{"from":"from-stone-500","to":"to-zinc-700","pattern":"circles"}', '["التسابق المحموم على ترويج الذات وإبداء الآراء الفورية في جميع الشؤون أفقدنا فضيلة تذوق الصمت والاصغاء البالغ والعميق لمشاكل الآخرين.","الإعراض والسكوت ليس جهلاً بالآراء، بل هو محاولة واعية لتصفيح العقل وحمايته من التلوث السمعي والاستهلاك اللحظي السطحي للكلمات.","عند تصالحك مع ذاتك، لن تجد ضرورة لإثبات صحة وجهة نظرك في كل مجلس، فالحكيم يعمل في هدوء وصمت وتتكلم عنه جودة إنجازاته الفريدة."]', NULL, '١٠ دقائق', '١٨ مايو ٢٠٢٦', 680, 142, 4.6);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-8', 'تطور المكتبات العربية من رزم الورق إلى السحابة الرقمية', 'د. مريم الدرعي', 'تاريخ وأدب', NULL, 'https://images.unsplash.com/photo-1524995997946-a1c2e315a42f?w=400&auto=format&fit=crop&q=80', '{"from":"from-amber-600","to":"to-rose-800","pattern":"clouds"}', '["تاريخ الحضارة العربية مرصوف بالكتب والورق الرائع، فقد كان للوراقين وبساتين المعارف شأن ريادي عظيم في صياغة الفنون وتوارث السير الفذة.","اليوم نلتقي بالسماء الرقمية السحابية الشاسعة، حيث يتشارك الملايين من الباحثين ملايين المخطوطات والتحقيقات العريقة بثانية واحدة.","نهدف من خلال رواقنا الرقمي إلى حماية هذه الهوية الأدبية السامقة وحفظ درر الكلمات في وعاء رقمي فاخر يسهل تصفحه لجميع الأجيال."]', NULL, '١٢ دقيقة', '١٢ مايو ٢٠٢٦', 1100, 198, 4.7);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-9', 'أثر الرضا والقناعة على صحة العقل وطمأنينة القلب الرسيخة', 'عبدالله الدرعي', 'تطوير الذات والروح', NULL, 'https://images.unsplash.com/photo-1499209974431-9dddcece7f88?w=400&auto=format&fit=crop&q=80', '{"from":"from-teal-400","to":"to-emerald-600","pattern":"waves"}', '["القناعة الحقيقية ليست خنوعاً أو كسلاً عن السعي، بل هي تسليم كامل وبصير لعدالة تقسيم الأرزاق مع الحفاظ على حماسة الطموح العالية.","الإنسان القنوع يتمتع بقلب هادئ يخلو من الضغائن والترهات والمقارنات المستمرة بالآخرين في شاشات هواتفهم الرقمية الباهتة.","عند تصالحك مع ذاتك وتقبل تفصيل حياتك برضا، ستمتنع عن إرهاق جسدك بالتوتر وتقوى مناعتك العقلية والروحية بمرور السنين والعهود."]', NULL, '٥ دقائق', '٥ مايو ٢٠٢٦', 840, 175, 4.5);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-10', 'مسالك الفهم ومفاتيح التفكير المنهجي الفلسفي', 'أديب الدرعي', 'فلسفة وتأمل', NULL, 'https://images.unsplash.com/photo-1516979187457-637abb4f9353?w=400&auto=format&fit=crop&q=80', '{"from":"from-violet-500","to":"to-indigo-800","pattern":"circles"}', '["البحث الفلسفي المنهجي يبدأ من طرح السؤال السليم المبسط بعيداً عن السفسطة اللغوية المفرغة المعيقة للوعي النظيف وتكامل المعرفة.","الفهم لا يتأتى بالاقتباس دون تفكير، بل بتفكيك الحجج وبناء أسس متينة من المقاربات العقلية التي تصمد أمام رياح التمحيص والنقد العلمي.","أفكارك هي البناية التي تملكها بمطاف الحياة؛ احرص على انتقاء مواد التأسيس وزين غرفها بحلى التواضع وحب الخير للجميع."]', NULL, '٩ دقائق', '٣٠ أبريل ٢٠٢٦', 1250, 254, 4.8);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-11', 'الكلمات المنسية: روائع من البلاغة العربية وتأثيرها المعاصر', 'سارة الدرعي', 'أدب ونقد', NULL, 'https://images.unsplash.com/photo-1457369804613-52c61a468e7d?w=400&auto=format&fit=crop&q=80', '{"from":"from-cyan-500","to":"to-sky-700","pattern":"clouds"}', '["اللغة العربية بحر شاسع يزخر بالدرر والكلمات المنسية التي تعطي للسطور بلاغة وجدانية ورصانة فكرية تتصاغر أمامها لغات الأرض قاطبة.","القالب البلاغي كالمجاز والتشبيه والاستعارة يمنح الأفكار أجنحة ملونة وسحر يربط عقل القارئ بوجدان وعاطفة الكاتب بشكل مذهل ورائع.","مقالنا اليوم يهدف لاستحضار عينات من الفصحى الرشيقة وإعادة استخدامها في كتاباتنا العصرية لتغذية الذوق الأدبي العام وحمايته من الوهن."]', NULL, '٧ دقائق', '٢٠ أبريل ٢٠٢٦', 910, 165, 4.7);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-12', 'في رحاب التدبر: كيف نحول القراءة إلى وعي وتطبيق؟', 'أبو حاتم الدرعي', 'عقيدة وتوحيد', NULL, 'https://images.unsplash.com/photo-1447069387593-a5de0862481e?w=400&auto=format&fit=crop&q=80', '{"from":"from-amber-700","to":"to-stone-900","pattern":"waves"}', '["التدبر في المكنونات الإيمانية والكتب الإسلامية المعتمدة هو المقصد الأسمى لطالب العلم الحريص على بناء وجدانه على السنة النبوية الصحيحة والقرآن العريق.","إن قراءة متن وتفهّم معانيه بعمق وترجمته لعمل يومي مبروك يفوق بكثير قراءة مجلدات ضخمة دون تصفية فكرية أو أثر واضح وملموس بالخلق والسلوك.","لنهتم بالتأصيل النظيف لعقيدتنا ونشرها بين عائلاتنا بروية ولطف واقتداء دائم برسول الإنسانية صلى الله عليه وعلى آله وسلم."]', NULL, '١١ دقيقة', '١٥ أبريل ٢٠٢٦', 1380, 310, 5);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-13', 'أسرار الانتاجية الإبداعية من خلال فترات الراحة المنظمة', 'مها الدرعي', 'تطوير الذات والروح', NULL, 'https://images.unsplash.com/photo-1512820790803-83ca734da794?w=400&auto=format&fit=crop&q=80', '{"from":"from-rose-500","to":"to-rose-700","pattern":"circles"}', '["يتسابق الناس في ترويج الإرهاق كمقياس للنجاح والكرامة المهنية، واعلم أن عقل الفرد يحتاج لفترات من الكمون والهدوء ليفجّر أفضل أفكاره الإبداعية الخلابة.","أخذ جولة قصيرة تحت ظلال الشجر أو تأمل سحابة تحلق بهدوء يحفز تدفق هرمونات السكينة ويعيد تنشيط الدوائر الدماغية للاستئناف بكفاءة أعلى.","الانتاجية ليست إهلاكاً للجسد بقدر ما هي تسيير منظم للمهارات وحيازة التركيز الكامل الصافي في اللحظات المناسبة الشغوفة."]', NULL, '٨ دقائق', '١٠ أبريل ٢٠٢٦', 795, 153, 4.6);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-14', 'دور الأدب الإنساني في تجسيد آلام وآمال المجتمعات المتكاملة', 'سارة الدرعي', 'أدب ونقد', NULL, 'https://images.unsplash.com/photo-1543002588-bfa74002ed7e?w=400&auto=format&fit=crop&q=80', '{"from":"from-violet-600","to":"to-pink-700","pattern":"waves"}', '["الأديب المخلص ليس ناقلاً بارداً للغة، بل هو مرآة نابضة ومستجيبة تعكس تطلعات قومه وتسجل آلامهم وآمالهم في أطر لغوية مفعمة بالاقتدار والوهج.","عظمة الروايات تكمن في تمثيل المشاعر الإنسانية المشتركة: دمعة الحنين، بهجة النقاء، ونبل التضحية من أجل رفعة وسعادة الآخرين الكرام.","عند قراءتنا للأعمال الأدبية الرفيعة، نستكشف أننا مترابطون على اختلاف ألسنتنا وبيئاتنا برباط إنساني رقيق يستحق منا الصدق وحسن الرعاية."]', NULL, '١٠ دقائق', '٥ أبريل ٢٠٢٦', 870, 139, 4.5);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-15', 'العزلة الإيجابية: متى يكون الانفراد بالذات مدعاة للإلهام؟', 'صالح الدرعي', 'تطوير الذات والروح', NULL, 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?w=400&auto=format&fit=crop&q=80', '{"from":"from-teal-500","to":"to-blue-700","pattern":"clouds"}', '["العزلة الباردة المؤذية تولد الاكتئاب، بينما العزلة الإيجابية الاختيارية هي طقس مقدس لتطهير الوجدان وترتيب فكر الفرد المبدع بعيداً عن التأثيرات الضارة.","في فترات الاختلاء بالكتب وحب التأمل، يعود الفرد لجوهر نفسه، ويتأهب ذهنياً وقيمياً للمودة وتقديم النفع للمجتمعات بروح جديدة وصافية متقدة.","الانسجام والسكينة ينبعان من هذه المساحة الهادئة التي تقضيها مع روحك، لتجود بعدها بغيث من العطاء والخير الميمون للأهل والأصحاب."]', NULL, '٨ دقائق', '١ أبريل ٢٠٢٦', 1040, 226, 4.8);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-16', 'عبقرية التبسيط: كيف تشرح الأفكار العميقة بكلمات ميسرة؟', 'أديب الدرعي', 'وعي فكري', NULL, 'https://images.unsplash.com/photo-1553729459-beb747028b42?w=400&auto=format&fit=crop&q=80', '{"from":"from-sky-500","to":"to-indigo-600","pattern":"circles"}', '["تنميق المصطلحات وتكلف الكلمات الفلسفية المعقدة ليس دليلاً على عمق الوعي، بل إن البراعة الحقيقية تكمن في تبسيط المادة لتصل لعقل الشاب البسيط بجمال ويسر.","صانع المحتوى الذكي يجرد الفكرة الصعبة من زوائدها ويعرض لبّها بمثال من واقع الحياة كحركات السحب والندى وزرع القلوب الطاهرة.","لنتعلم فنون التبسيط في جميع علومنا، فالهدف من نشر الوعي هو التنوير العام وتعميم المنفعة وليس بناء جزر معزولة من النخبوية العاجزة."]', NULL, '٧ دقائق', '٢٨ مارس ٢٠٢٦', 1180, 247, 4.9);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-17', 'تآلف الأرواح وفلسفة العلاقات الإنسانية الصادقة', 'مها الدرعي', 'فلسفة وتأمل', NULL, 'https://images.unsplash.com/photo-1516589178581-6cd7833ae3b2?w=400&auto=format&fit=crop&q=80', '{"from":"from-rose-400","to":"to-rose-600","pattern":"waves"}', '["العلاقات المتينة لا تستند بالضرورة على تشابه الاهتمامات السطحية، بل على تآلف القلوب وتلاقي المعايير والمبادئ الأخلاقية الصادقة.","إن الصديق المخلص والمحب هو الذي يقبل ضعفك ويقوي همتك، ويوجهك بحكمة وهدوء نحو العطاء والنقاء مع تقديم الدعم دون توقع الرد اللحظي.","لنستثمر في العلاقات الدافئة التي تمنحنا السلام والطاقة الإيجابية، فهي السند الحقيقي لنا للتغلب على عشوائية وبطش الحياة المعاصرة."]', NULL, '٩ دقائق', '٢٠ مارس ٢٠٢٦', 830, 181, 4.7);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-18', 'الكتاب سفيراً بين الحضارات ومصلحاً للاختلافات الثقافية', 'د. مريم الدرعي', 'تاريخ وأدب', NULL, 'https://images.unsplash.com/photo-1513001900722-370f803f498d?w=400&auto=format&fit=crop&q=80', '{"from":"from-amber-500","to":"to-amber-800","pattern":"clouds"}', '["تاريخ الحضارة البشرية يروي لنا الكثير من قصص الحروب والعداء، ولكن الترجمة وحركة الكتب كانت دوماً هي الجسر السري الذي يصل الأرواح بالعلوم ويصحح الخرافات.","من خلال معرفة تراث الآخرين وفهم طريقتهم بطلب الحكمة والجمال، يزول الخوف وتتنزل مشاعر الود وتتكامل المعرفة لخدمة البشرية جمعاء.","رواقنا الوجداني يؤمن بأهمية الكلمة كسفير طاهر يداوي شقاق القلوب ويعيد صياغة المستقبل بروح من الاحترام والود العالي النقي."]', NULL, '١٠ دقائق', '١٠ مارس ٢٠٢٦', 940, 148, 4.6);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-19', 'حكمة الزمان: تأملات في تغير الفصول كمرآة للحياة البشرية', 'عبدالله الدرعي', 'فلسفة وتأمل', NULL, 'https://images.unsplash.com/photo-1425913397330-cf8af2ff40a1?w=400&auto=format&fit=crop&q=80', '{"from":"from-emerald-600","to":"to-emerald-800","pattern":"waves"}', '["تداول الفصول الأربعة بين عواصف الشتاء الحاد والربيع المورق بهجة النماء هو التجسيد الأكمل لطقوس وتقلبات الحياة النفسية لجميع البشر الكرام.","الصبر في الخريف حين تسقط الأوراق الميتة ليس استسلاماً للموت، بل هو حتمية التقبل الذكي لتهيئة التربة من أجل ولادة زهور الربيع اليانعة.","دورتك الداخلية تحتاج لمواسمها الخاصة؛ لا بأس ببعض فترات الكمون والراحة، طالما أن الروح ما زالت متطلعة لشمس الإنجاز والهداية السامية."]', NULL, '٦ دقائق', '٣ مارس ٢٠٢٦', 710, 164, 4.8);

INSERT INTO `articles` (`id`, `title`, `author`, `category`, `description`, `cover_image`, `image_style`, `content`, `rich_content`, `read_time`, `date`, `views`, `likes`, `rating`) 
VALUES ('a-20', 'جماليات الخط العربي وتأثير الهوية البصرية على نفوس القراء', 'سارة الدرعي', 'أدب ونقد', NULL, 'https://images.unsplash.com/photo-1455390582262-044cdead277a?w=400&auto=format&fit=crop&q=80', '{"from":"from-violet-500","to":"to-rose-600","pattern":"circles"}', '["الخطوط العربية اليدوية والرقمية المتقنة من ثلث أو كوفي أو ديواني رصين تضفي على الصحائف جمالاً فائقاً وتطرب عين القارئ اللطيف قبل الولوج العالي للمعاني.","الهوية البصرية والنقاء التنسيقي الذي نتبناه في رواق الدرعي الرقمي يهدف لتكامل المتعة النفسية لتعيش الحواس جميعها تجربة المطالعة الأبهى.","الفن البصري الجميل الطاهر يهذب النفوس ويمد القارئ بروحانية تسبق التغيير وتخلق اتصالاً فريداً بآثار وموروث الرواد الأوائل الكرام في مجالاتنا."]', NULL, '٩ دقائق', '٢٨ فبراير ٢٠٢٦', 1150, 215, 4.8);


-- Seeding Thoughts --
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-1', 'نور الحكمة والصفاء', 'المكتبات ليست مجرد رفوف مرصوصة، بل هي بوابات زمنية تعبر بنا بين عقول الفلاسفة وأرواح الشعراء دون حاجة لمغادرة مقاعدنا القيّمة.', 'أديب الدرعي', 'تأملات', 'منذ يومين', 42, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-2', 'زهرة الروح والورق', 'كل كتاب تقرؤه يزرع في روحك زهرة فكرية فريدة، ترويها خيالاتك وتزهر في كلماتك وأفعالك اليومية.', 'عبدالله الدرعي', 'إلهام', 'منذ ٣ أيام', 56, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-3', 'غيث المعرفة والسحاب', 'مثل السحاب الذي يجود بالمطر غيثاً للأرض العطشى، تجود الحكمة بالمعرفة غياثاً للعقول الظمأى.', 'مها الدرعي', 'حكمة', 'منذ أسبوع', 83, 4, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-4', 'تخليد اللحظات العابرة', 'الكتابة هي محاولة بائسة ولكنهما رائعة لتخليد اللحظة العابرة ولتجسيد المشاعر التي تعجز الأفواه عن صياغتها بصوت جهور.', 'سارة الدرعي', 'أدب', 'منذ ٥ أيام', 29, 4, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-5', 'دروس السماء المجانية', 'أن تنظر إلى السماء الزرقاء وتتأمل السحب المتفرقة، هو درس مجاني في المرونة؛ فالغيوم ترحل والصفاء باقٍ على الدوام كروحك النقية.', 'فيلسوف الدرعي', 'فلسفة', 'منذ ساعتين', 112, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-6', 'الورق صدى الصمت', 'الصمت في حضور الكتب هو شكل من أشكال الحوار الراقي والمؤنس، حيث تصمت ألسنتنا لتتحدث عقولنا بلغة النور والصفاء الجوهري.', 'أبو حاتم الدرعي', 'تأملات', 'منذ يومين', 38, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-7', 'الغيوم والوعي البديل', 'لا تبحث عن الصفاء في زحام الماديات، بل انظر إلى السحب السابحة في الأعالي؛ ستعلم أن كل ما يعيق رحلتك اليوم هو عابر مثل تلك الغيوم الرقيقة.', 'صالح الدرعي', 'فلسفة', 'منذ يومين', 47, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-8', 'الرحلة بين دفتي كتاب', 'من لم يقرأ إلا كتاباً واحداً لم يعش إلا كحياة واحدة عابرة، أما الفكر المتدبر فيعيش آلاف السنين متنقلاً بين صفحات التاريخ والحكمة العريقة.', 'عبدالله الدرعي', 'إلهام', 'منذ ٤ أيام', 64, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-9', 'تأملات في كوب قهوة', 'امتزاج رائحة الورق العتيق بنكهة القهوة الدافئة في ركن هادئ، يمثل توازناً فريداً بين يقظة الذهن وسلطنة الطمأنينة الروحية الرائعة.', 'مريم الدرعي', 'إلهام', 'منذ ٥ أيام', 72, 4, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-10', 'همسات الفجر والرضا', 'نسمات الصباح الباكر تحمل دائماً وعوداً متجددة من الخالق؛ رتب أفكارك مع خيوط النور الأولى، واعلم أن عسرك متبوع بيسر عظيم يفيض بالحب والجمال.', 'مها الدرعي', 'تأملات', 'منذ ٦ أيام', 51, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-11', 'نقاء الذهن والكلمات', 'الكلمة الطيبة هي غرس طيب ينبت في القلوب وعياً ومحبة، بينما تغسل الكلمات العذرة غبار الضغائن وتورث النفوس سلاماً داخلياً لا ينقطع.', 'سارة الدرعي', 'أدب', 'منذ أسبوع', 36, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-12', 'سلام الأرواح بين الحروف', 'التصالح مع الذات يبدأ من فهم عوالمنا الداخلية وتدوين مشاعرنا دون خجل أو تردد؛ الحروف هي مرايا شفافة لمدى الرقي الإنساني.', 'أديب الدرعي', 'حكمة', 'منذ ٩ أيام', 88, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-13', 'أشواق قرائية متمهلة', 'حب المطالعة ليس سباقاً لإنهاء عدد هائل من السطور، بل هو متعة التوقف عند الجملة البديعة وتكرار تأملها حتى تتمازج بالدم والفكر الملهم.', 'أبو حاتم الدرعي', 'تأملات', 'منذ ١٠ أيام', 41, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-14', 'نور الغمام والصحائف', 'الصحيفة التي تحمل وعياً طاهراً تُنير دروب الحيارى كالسراج في دياجير الظلام السقيم، لنهتم بمداد ما نكتب لمنفعة الأمة وصعود همتها.', 'فيصل الدرعي', 'إلهام', 'منذ ١٢ يوماً', 33, 4, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-15', 'سحر الليل الوجداني', 'في عتمة الليل البهيم، ترتاح النفوس وتطير الأفكار نحو ملكوت السموات، متدبرة في بديع صنع الخالق وطالبة للهدى والنقاء الباقي.', 'مريم الدرعي', 'حكمة', 'منذ أسبوعين', 95, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
VALUES ('t-16', 'منبع السكينة في القراءة', 'كلما شعرت باضطراب أفكار العالم وصخب الإعلام، تذكر أن بين دفتي كتابك الكلاسيكي المفضل واحة آمنة لا عاصفة فيها ولا تضليل العقول.', 'صالح الدرعي', 'تأملات', 'منذ يومين', 59, 5, 0);
INSERT INTO `thoughts` (`id`, `title`, `content`, `author`, `category`, `date`, `likes`, `rating`, `views`) 
